const container=document.querySelector(".fireworks"),fireworks=new Fireworks.default(container);function scrollToElement(e,o){setTimeout(function(){var o=document.getElementById(e);o?o.scrollIntoView({behavior:"smooth",block:"start",block:"center"}):console.error("Element with id '"+e+"' not found.")},1e3*o)}fireworks.start(),scrollToElement("scroll",3);